steps.prompt:
forge build --build-info --out .recon/out > /tmp/recon-build.log 2>&1;
BUILD_EXIT=$?;
cat /tmp/recon-build.log;

if [ $BUILD_EXIT -ne 0 ] && grep -qE 'Error \(1834\)|Copying of type struct.*not yet supported' /tmp/recon-build.log; then
  echo '>>> via_ir compilation error detected. Adding via_ir = true and retrying... <<<';
  if grep -qE '^via[_-]ir\s*=\s*false' foundry.toml 2>/dev/null; then
    sed -i 's/^via[_-]ir\s*=\s*false/via_ir = true/' foundry.toml;
  elif ! grep -qE '^via[_-]ir\s*=\s*true' foundry.toml 2>/dev/null; then
    if grep -q '^\[profile\.default\]' foundry.toml 2>/dev/null; then
      sed -i '/^\[profile\.default\]/a via_ir = true' foundry.toml;
    elif grep -n '^\[' foundry.toml 2>/dev/null | head -1 | grep -q .; then
      FIRST_SEC=$(grep -n '^\[' foundry.toml | head -1 | cut -d: -f1);
      sed -i "${FIRST_SEC}i via_ir = true" foundry.toml;
    else
      printf '\nvia_ir = true\n' >> foundry.toml;
    fi;
  fi;
  rm -rf .recon/out;
  forge build --build-info --out .recon/out;
elif [ $BUILD_EXIT -ne 0 ]; then
  exit $BUILD_EXIT;
fi;

BI_FILE=$(find .recon/out/build-info -name '*.json' -not -name '*.filtered.json' 2>/dev/null | head -1);
if [ -n "$BI_FILE" ]; then filter-build-info "$BI_FILE" -o "$BI_FILE"; fi;
echo 'Recon build output ready.'
